class Solution:
    def findMedianSortedArrays(self, nums1: List[int], nums2: List[int]) -> float:
        if not nums1:
            return nums2[len(nums2)//2]
        if not nums2:
            return nums1[len(nums1)//2]

        left = 0
        right = len(nums1) -1
        target = (len(nums1) + len(nums2)) // 2
        mid, mid2 = 0, 0

        while left <= right:
            mid = (left + right) // 2
            mid2 = bisect.bisect_left(nums2, nums1[mid])
            temp = mid + mid2 + 2
            if len(nums2) > mid2 and nums1[mid] < nums2[mid2]:
                temp -= 1

            if temp == target:
                break
            elif temp < target:
                left = mid + 1
            else:
                right = mid - 1


        if (len(nums1) + len(nums2)) % 2 == 0: # even
            if len(nums2) <= mid2:
                return (nums2[-1] + nums2[-2]) / 2
            elif mid2 == 0 and len(nums1) - 1 == mid:
                return (nums1[-1] + nums1[-2]) / 2
            else:
                return (nums1[mid] + nums2[mid2]) / 2
        else: # odd
            numbers = [nums1[mid], nums2[mid2], nums1[mid + 1]]
            numbers.sort()
            return numbers[1]

class Solution:
    def findMedianSortedArrays(self, nums1: List[int], nums2: List[int]) -> float:
        size1 = len(nums1)
        size2 = len(nums2)

        if size1 > size2:
            size1, size2 = size2, size1
            nums1, nums2 = nums2, nums1

        summ = size1 + size2
        left = (summ + 1) // 2
        low = 0
        high = size1

        while low <= high:
            mid1 = (low + high) // 2
            mid2 = left - mid1

            left1 = -sys.maxsize
            left2 = -sys.maxsize
            right1 = sys.maxsize
            right2 = sys.maxsize

            if mid1 < size1:
                right1 = nums1[mid1]
            if mid2 < size2:
                right2 = nums2[mid2]
            if mid1 - 1 >= 0:
                left1 = nums1[mid1 - 1]
            if mid2 - 1 >= 0:
                left2 = nums2[mid2 - 1]

            if left1 <= right2 and left2 <= right1:
                if summ % 2 == 0:
                    return (max(left1, left2) + min(right1, right2)) / 2
                else:
                    return max(left1, left2)
            elif left1 > right2:
                high = mid1 -1
            else:
                low = mid1 + 1

        return 0.0
